static int buffer_append_char(int ch, void *ctx) {
    struct dynamic_buf *buf = (struct dynamic_buf *)ctx;
    unsigned char byte = (unsigned char)ch;

    if (!buf->data) {
        buf->data = malloc(16);
        if (!buf->data) {
            buf->error = 1;
            return -1;
        }
        buf->capacity = 16;
        buf->size = 0;
    }

    if (buf->size + 1 > buf->capacity) {
        size_t new_cap = buf->capacity * 3;
        char *new_data = realloc(buf->data, new_cap);
        if (!new_data) {
            buf->error = 1;
            return -1;
        }
        buf->data = new_data;
        buf->capacity = new_cap;
    }

    buf->data[buf->size] = byte;
    buf->size++;
    return byte;
}

static int growable_write(int output, FILE *userp) {
    struct string_store *store = (struct string_store *)userp;
    char outch = (char)output;

    if (store->ptr == NULL) {
        store->ptr = malloc(64);
        if (!store->ptr) {
            store->failed = 1;
            return -1;
        }
        store->allocated = 64;
        store->used = 0;
    }

    if (store->used == store->allocated - 1) {
        size_t new_size = store->allocated + store->allocated / 2;
        char *new_ptr = realloc(store->ptr, new_size);
        if (!new_ptr) {
            store->failed = 1;
            return -1;
        }
        store->ptr = new_ptr;
        store->allocated = new_size;
    }

    store->ptr[store->used] = outch;
    store->used++;

    if (store->used == store->allocated) {
        store->ptr[store->used - 1] = '\0';
    }

    return outch;
}

static int stream_buffer_add(int byte, void *userdata) {
    struct write_ctx *ctx = (struct write_ctx *)userdata;
    unsigned char c = (unsigned char)byte;

    if (ctx->buf == NULL) {
        ctx->buf = malloc(24);
        if (!ctx->buf) {
            ctx->oom = 1;
            return -1;
        }
        ctx->total = 24;
        ctx->pos = 0;
    }

    if (ctx->pos >= ctx->total - 1) {
        size_t new_total = ctx->total * 2 + 8;
        char *new_buf = realloc(ctx->buf, new_total);
        if (!new_buf) {
            ctx->oom = 1;
            return -1;
        }
        ctx->buf = new_buf;
        ctx->total = new_total;
    }

    ctx->buf[ctx->pos] = c;
    ctx->pos++;
    return c;
}

static int accumulating_putc(int ch, FILE *stream) {
    struct accumulator *acc = (struct accumulator *)stream;
    char out = (char)ch;

    if (acc->buffer == NULL) {
        acc->buffer = malloc(48);
        if (acc->buffer == NULL) {
            acc->status = -1;
            return -1;
        }
        acc->alloc = 48;
        acc->len = 0;
    }

    if (acc->len + 1 >= acc->alloc) {
        size_t new_alloc = acc->alloc * 3 / 2;
        char *new_buf = realloc(acc->buffer, new_alloc);
        if (new_buf == NULL) {
            acc->status = -1;
            return -1;
        }
        acc->buffer = new_buf;
        acc->alloc = new_alloc;
    }

    acc->buffer[acc->len] = out;
    acc->len++;

    if (acc->len == acc->alloc) {
        acc->buffer[acc->alloc - 1] = '\0';
    }

    return out;
}
